import { lookupItemDetail, type ChatStateLists } from "./toolCalling";

const state: ChatStateLists = {
  inventory: [
    { item: "Rezavý meč", qty: 1, note: "Nalezen v kryptě, +1 k zastrašení" },
    { item: "Pochodeň", qty: 3 },
